sql:
SELECT e.employee_name, a.action
FROM employees e
INNER JOIN access_logs a ON e.employee_id = a.employee_id;

SELECT c.customer_name, c.email 
FROM customers c 
WHERE c.customer_id IN (
    SELECT customer_id FROM fitting_room
) 
AND c.customer_id NOT IN (
    SELECT customer_id FROM returns
);

SELECT COUNT(*)
FROM fitting_room
WHERE fitting_status = 'completed';

SELECT customers.customer_name, size_preferences.preferred_size
FROM customers
INNER JOIN size_preferences ON customers.customer_id = size_preferences.customer_id;

SELECT c.customer_name
FROM customers c
JOIN fitting_room fr ON c.customer_id = fr.customer_id;

SELECT AVG(c.height) AS average_height
FROM customers c
WHERE JSON_EXTRACT(c.purchase_history, '$.items') IS NOT NULL;

SELECT 
    (SELECT AVG(age) FROM customers) AS average_customer_age,
    (SELECT AVG(access_level) FROM employees) AS average_employee_access_level;

SELECT COUNT(DISTINCT fitting_room.customer_id) 
FROM fitting_room 
WHERE fitting_room.feedback = 'Good fit';

SELECT COUNT(DISTINCT department) AS UniqueDepartments
FROM employees
WHERE access_level = 2;
